import{_ as t,o as a,c as i,ao as r}from"./chunks/framework.D6W02q3u.js";const h=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":null}'),s={name:"roadmap.md"};function o(n,e,l,d,p,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="Roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#Roadmap" aria-label="Permalink to &quot;Roadmap {#Roadmap}&quot;">​</a></h1><p>GLLVM.jl is being built as a fast Julia <strong>digital twin of <a href="https://itchyshin.github.io/gllvmTMB/" target="_blank" rel="noreferrer"><code>gllvmTMB</code></a></strong>: the same model syntax, usable directly in Julia and (in the future) through R, across all response families. The live, detailed roadmap — with linked issues — is tracked on GitHub:</p><p>➡️ <strong><a href="https://github.com/itchyshin/GLLVM.jl/issues/11" target="_blank" rel="noreferrer">GLLVM.jl roadmap (issue #11)</a></strong></p><p>Current sequencing is R-first. Native <code>gllvmTMB</code> functionality and the R user workflow define the oracle; <code>GLLVM.jl</code> mirrors admitted rows, supplies parity evidence, and accelerates them after point estimates, logLik/objective, CI or CI-status, docs, tests, and Rose audit agree. REML is Gaussian-only; AI-REML is future design input for exact Gaussian cells, not non-Gaussian Laplace.</p><h2 id="Phase-release-map" tabindex="-1">Phase → release map <a class="header-anchor" href="#Phase-release-map" aria-label="Permalink to &quot;Phase → release map {#Phase-release-map}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Release</th><th style="text-align:right;">Theme</th><th style="text-align:right;">Highlights</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>v0.2.0</strong></td><td style="text-align:right;">Gaussian complete</td><td style="text-align:right;">closed-form marginal, O(p) phylogenetic fitter, post-fit tools, this docs site</td></tr><tr><td style="text-align:right;"><strong>v0.3.0</strong></td><td style="text-align:right;">Non-Gaussian catch-up</td><td style="text-align:right;">one-part Laplace families, first two-part fitters, analytic-gradient hardening</td></tr><tr><td style="text-align:right;"><strong>v0.4.0</strong></td><td style="text-align:right;">Interface and bridge catch-up</td><td style="text-align:right;"><code>@formula</code> front-end, wide/long parity, gllvmTMB-mirroring tutorials, live <code>gllvmTMB</code> bridge gates</td></tr><tr><td style="text-align:right;"><strong>v1.0</strong></td><td style="text-align:right;">Full digital twin</td><td style="text-align:right;">extractor / ordination / diagnostic parity, structured non-Gaussian dependence, complete R bridge coverage for supported models</td></tr></tbody></table><h2 id="What-works-today" tabindex="-1">What works today <a class="header-anchor" href="#What-works-today" aria-label="Permalink to &quot;What works today {#What-works-today}&quot;">​</a></h2><ul><li><p>Gaussian + phylogenetic GLLVM fitting (closed-form Gaussian marginal).</p></li><li><p>An <strong>O(p)</strong> phylogenetic gradient — exact, linear-in-species scaling.</p></li><li><p>Wald / profile-likelihood / parametric-bootstrap confidence intervals, including derived quantities (Sigma_y, communality, phylogenetic signal), where the family/structure row has passed its local evidence gate.</p></li><li><p>One-part Laplace families through <code>fit_gllvm</code>: Binomial, Poisson, NegativeBinomial, Beta, Ordinal, and Gamma.</p></li><li><p>Wald/profile confidence-interval routes for scalar-dispersion one-part Laplace families; grouped-dispersion bridge endpoints remain explicit unavailable status rows while parity and bridge exposure are audited.</p></li><li><p>Dedicated two-part fitters for Delta-lognormal, Hurdle-Poisson, and Hurdle-NB.</p></li><li><p>Minimal Julia-side <code>bridge_fit</code> for no-covariate one-part families, selected fixed-effect-X / missing-response rows, and complete Gaussian point-estimate <code>X_lv</code> rows tested by the paired <code>gllvmTMB</code> branch.</p></li></ul><h2 id="What&#39;s-planned" tabindex="-1">What&#39;s planned <a class="header-anchor" href="#What&#39;s-planned" aria-label="Permalink to &quot;What&#39;s planned {#What&#39;s-planned}&quot;">​</a></h2><ul><li><p><strong>Non-Gaussian inference hardening</strong> — R-parity evidence, derived covariance summaries, and bridge exposure beyond the current one-part CI routes.</p></li><li><p><strong>Structured non-Gaussian dependence</strong> — phylogenetic, animal, and spatial covariance in the Laplace path.</p></li><li><p><strong>Zero-inflated and additional two-part families</strong> — ZIP/ZINB and Delta-Gamma after the current two-part substrate hardens.</p></li><li><p><strong>Same-as-R model syntax</strong>: <code>gllvm(@formula(traits(...) ~ ... + phylo(...)), data; family = ...)</code>.</p></li><li><p><strong>The R bridge</strong> — keep the live <code>gllvmTMB</code> JuliaCall route as the admission oracle, then widen deliberately from the current partial rows: fixed-effect <code>X</code> for selected one-part families, response masks for selected no-X non-Gaussian families, complete balanced mixed-family no-X/no-mask/no-CI point fits, and in-sample post-fit methods. Remaining bridge work is X+mask, mixed-family X/masks/CIs, ordinal prediction payloads, newdata, richer diagnostics, and parity evidence for every promoted row.</p></li></ul><p>This roadmap evolves; issue #11 is always current.</p>',11)])])}const m=t(s,[["render",o]]);export{h as __pageData,m as default};
